mapper.select:
SELECT id, upload_complete, promotion_success, system_updates, updated_at
FROM notification_preference
WHERE id = #{id}

mapper.update:
UPDATE notification_preference
SET upload_complete = #{uploadComplete},
    promotion_success = #{promotionSuccess},
    system_updates = #{systemUpdates},
    updated_at = #{updatedAt}
WHERE id = #{id, typeHandler=com.grace.platform.shared.infrastructure.persistence.typehandler.NotificationPreferenceIdTypeHandler}
